import React, { useState } from 'react';
import { Menu, Layout } from 'antd';
import { HomeOutlined, PlusCircleFilled, UserOutlined } from '@ant-design/icons';
import { Link } from 'react-router-dom';
import './index.scss';

const { Footer } = Layout;

const menuItems = [{
  key: 'home',
  label: <Link to="/">首页</Link>,
  icon: <HomeOutlined />,
},
{
  key: 'new',
  // label: '发帖',
  icon: <PlusCircleFilled />,
  disabled: true,
},
{
  key: 'personal',
  label: <Link to="/personal">我的</Link>,
  icon: <UserOutlined />,
}]

const MainFooter = () => {
  const [current, setCurrent] = useState('home');
  const onMenuClick = e => {
    console.log('click ', e);
    setCurrent(e.key);
  };
  return (
    <Footer>
      <Menu onClick={onMenuClick} selectedKeys={[current]} mode="horizontal" items={menuItems} disabledOverflow={true} />
    </Footer>
  )
}
export default MainFooter;
