import React, { useState, useEffect } from 'react';
import { LaptopOutlined, LockOutlined, LogoutOutlined, UserOutlined, HomeOutlined, MessageOutlined } from '@ant-design/icons';
import { Layout, Menu, Dropdown, Avatar } from 'antd';
import { Link, Outlet, useLocation, Navigate } from 'react-router-dom';
import logo from '@/assets/logo.png'
import CusFooter from '@/pages/common/mainfooter/index';
import './index.scss';

const { Content, Sider, Header } = Layout;

const siderItems = [
  {
    key: '0',
    icon: <HomeOutlined />,
    label: <Link to='/'>返回首页</Link>,
  },
  {
    key: '1',
    icon: <UserOutlined />,
    label: <Link to='/personal/info'>个人资料</Link>,
  },
  {
    key: '2',
    icon: <LaptopOutlined />,
    label: <Link to='/personal/posts'>我的帖子</Link>,
  },
  {
    key: '3',
    icon: <LockOutlined />,
    label: <Link to='/personal/modify'>修改密码</Link>,
  },
  { type: 'divider', },
  {
    key: '4',
    icon: <LogoutOutlined />,
    label: '退出登录',
    danger: true,
  },
];

const dropdownItems = [
  {
    key: '1',
    label: (
      <a href="/personal">
        <UserOutlined /> 个人中心
      </a>
    ),
  },
  {
    key: '2',
    label: (
      <a target="_blank" rel="noopener noreferrer" href="https://www.aliyun.com">
        <MessageOutlined /> 通知消息
      </a>
    ),
  },
  { type: 'divider', },
  {
    key: '3',
    danger: true,
    label: (
      <a href="/login">
        <LogoutOutlined /> 退出登录
      </a>
    ),
  },
];

const Personal = () => {
  const location = useLocation();
  const [isMobile, setIsMobile] = useState(window.innerWidth <= 480);
  const [showContent, setShowContent] = useState(true);

  // 监听屏幕宽度变化
  useEffect(() => {
    const handleResize = () => {
      setIsMobile(window.innerWidth <= 480);
    };

    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // 监听路由变化，控制 Content 显示
  useEffect(() => {
    // 只在移动端控制平移效果
    if (isMobile) {
      if (location.pathname !== '/personal') {
        setShowContent(false);
      } else {
        setShowContent(true);
      }
    } else {
      // PC端始终显示
      setShowContent(true);
    }
  }, [location, isMobile]);

  // 如果电脑端访问根路径，重定向到 /info
  if (!isMobile && location.pathname === '/personal') {
    return <Navigate to="/personal/info" replace />;
  }

  return (
    <div className='personal'>
      <Layout>
        <Header>
          <div className="demo-logo">
            <Link to="/home">
              <img src={logo} alt="" height={64} />
            </Link>
          </div>
          <div className="app-avatar" >
            <Dropdown menu={{ items: dropdownItems }} placement="bottomRight" arrow={{ pointAtCenter: true }}>
              <Avatar size='large' icon={<UserOutlined />} />
            </Dropdown>
          </div>
        </Header>

        <Layout>
          <Sider>
            <Menu
              mode="inline"
              selectedKeys={[location.pathname]}
              items={siderItems}
            />
          </Sider>
          <Content className={isMobile ? (showContent ? 'content-enter' : 'content-exit') : ''}>
            <div className='personal-content'>
              <Outlet />
            </div>
          </Content>
        </Layout>
        <CusFooter />
      </Layout>
    </div>
  );
};

export default Personal;